import { useState, createContext, useContext, useEffect } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  
  // Initialize order state from localStorage if available
  const [order, setOrder] = useState(() => {
    const savedOrder = localStorage.getItem("order");
    return savedOrder ? JSON.parse(savedOrder) : {};
  });
  
  const [menu, setMenu] = useState([]);

  // Persist order to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem("order", JSON.stringify(order));
  }, [order]);

  const addToOrder = (ProductId) => {
    setOrder((prev) => ({
      ...prev,
      [ProductId]: (prev[ProductId] || 0) + 1,
    }));
  };

  const removeItem = (ProductId) => {
    setOrder((prev) => {
      const temp = { ...prev };
      delete temp[ProductId];
      return temp;
    });
  };

  const removeFromOrder = (ProductId) => {
    if (order[ProductId]) {
      setOrder((prev) => ({
        ...prev,
        [ProductId]: prev[ProductId] - 1,
      }));
    }
  };

  return (
    <OrderContext.Provider
      value={{ order, addToOrder, menu, setMenu, removeFromOrder, removeItem }}
    >
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
